/** UsptCnvnApplcntHistDao.insert */
insert into uspt_cnvn_applcnt_hist (
		 cnvn_applcnt_hist_id
		,cnvn_change_req_id
		,confm_cnvn_applcnt_hist_id
		,applcnt_nm
		,gender_cd
		,enc_mbtlnum
		,enc_brthdy
		,native
		,enc_email
		,indvdl_bsnm_div_cd
		,charger_nm
		,ceo_nm
		,bizrno
		,charger_mbtlnum
		,charger_email
		,creator_id
		,created_dt
	) values (
		 #{cnvnApplcntHistId}
		,#{cnvnChangeReqId}
		,#{confmCnvnApplcntHistId}
		,#{applcntNm}
		,#{genderCd}
		,#{encMbtlnum}
		,#{encBrthdy}
		,#{nativeYn}
		,#{encEmail}
		,#{indvdlBsnmDivCd}
		,#{chargerNm}
		,#{ceoNm}
		,#{bizrno}
		,#{chargerMbtlnum}
		,#{chargerEmail}
		,#{creatorId}
		,#{createdDt}
	)
